            Green.enabled = true;
            Red.enabled = false;
            yield return new WaitForSeconds(30);
            Debug.Log("on");
            Yellow.enabled = true;
            Green.enabled = false;
            yield return new WaitForSeconds(5);
            Debug.Log("on");
            Red.enabled = true;
            Yellow.enabled = false;
            yield return new WaitForSeconds(30);

        }

    }


